如果使用标准的I2C通信时序，则HAL库提供直接的Memory读写函数
HAL_I2C_Master_Transmit();HAL_I2C_Master_Receive();HAL_I2C_Slave_Transmit();HAL_I2C_Slave_Receive();HAL_I2C_Mem_Write();HAL_I2C_Mem_Read();HAL_I2C_IsDeviceReady();
也可以使用Master_Transmit自行组合时序，这和Linux下读写I2C总线差不多

按照编译器分为GNUC和KEIL的ARMCC /* 重定向printf */#ifdef __GNUC__    #define PUTCHAR_PROTOTYPE  int __io_putchar(int ch)#else    #define PUTCHAR_PROTOTYPE  int fputc(int ch, FILE *stream)#endifPUTCHAR_PROTOTYPE &#123;    UART_Debug_Buff[UART_Debug_BuffIndex] = (uint8_t) ch;    UART_Debug_BuffIndex ++;    return ch;&#125;

按照使用MicroLib和不使用MicrlLib，不使用MicroLib时用到半主机模式

半主机模式的重定向方法如下

#pragmaimport(__use_no_semihosting)struct __FILE &#123;    int handle;&#125;;FILE __stdout;_sys_exit(int x) &#123;    x = x;&#125;int fputc(int ch, FILE*f) &#123;    while((USART1-&gt;SR&amp;0X40)==0);    USART1-&gt;DR =(u8) ch;    return ch;&#125;

使用MicroLib重定向方法如下

int fputc(int ch, FILE *stream) &#123;    return ch;&#125;

STM32CubeIDE中重定向printf，%f失效
